@startuml
class Character {
  -{field} GameDataRef _data;
  -{field} sf::Sprite sprite;
  -{field} sf::Vector2f position;
  -{field} sf::Texture texture;
  -{field} sf::Texture texture_flip;
  -{field} sf::Texture run_right1;
  -{field} sf::Texture run_right2;
  -{field} sf::Texture run_left1;
  -{field} sf::Texture run_left2;
  -{field} bool flip = false;
  -{field} sf::Clock animationClock;
  -{field} int animationRun = 0;
  -{field} bool air_texture = false;

  #{field} sf::Vector2f velocity = {0,0};
  #{field} float speed = 400.0f;
  #{field} float jump_speed = 600.0f;
  #{field} float slow_down = 0.0f, slow_down_ground = 40.0f, slow_down_air = 5.0f;
  #{field} float speed_up = 0.0f, speed_up_ground = 40.0f, speed_up_air = 30.0f;
  #{field} int max_jump =1, jump = 0;
  #{field} bool jump_done = false, on_ground = false;

  -{method} void flipTexture();

  +{method} Character(GameDataRef data);
  +{method} void update();
  +{method} void setTexture(6 Textures);
  +{method} void setPosition(const sf::Vector2f& position_);
  +{method} void setPosition(const float& x, const float& y);
  +{method} sf::Vector2f getPosition();
  +{method} void draw(sf::RenderWindow& renderWindow);
  +{method} void move(sf::Vector2f movement);
  +{method} void move(const float& x, const float& y);
  +{method} sf::Vector2f nextPosition(sf::Vector2f movement);
  +{method} sf::Sprite nextSprite(sf::Vector2f movement);
  +{method} sf::Sprite& getSprite();
  +{method} bool objectCollisionAndFalling(const sf::Sprite &object, const float& dt);
  +{method} void updateVelocity(const float& dt);
  +{method} void respawn(sf::Vector2f spawn);
  +{method} void characterKeyboardInput();
}
@enduml
